import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface Clock {
  city: string;
  localTime: string;
  dateDifference: string;
}

interface WidgetData {
  clocks: Clock[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { clocks } = widgetData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 380,
        bgcolor: theme === 'dark' ? '#1E1E1E' : '#FFFFFF',
        color: '#FFFFFF',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={1}>
          <Typography variant="h6" sx={{ color: primaryColor }}>
            World Clock
          </Typography>
          {clocks.map((clock, index) => (
            <Box key={index} sx={{ mb: 1 }}>
              <Typography variant="body1" sx={{ fontWeight: 500, color: accentColor }}>
                {clock.city}
              </Typography>
              <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                {clock.localTime} - {clock.dateDifference}
              </Typography>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
